import{_ as i,c as a,o as e,ah as l}from"./chunks/framework.DwHsq7Fg.js";const g=JSON.parse('{"title":"Основы Docker: Мониторинг","description":"","frontmatter":{},"headers":[],"relativePath":"basic_docker/docker_monitoring.md","filePath":"basic_docker/docker_monitoring.md"}'),n={name:"basic_docker/docker_monitoring.md"};function r(t,s,h,o,k,p){return e(),a("div",null,s[0]||(s[0]=[l(`<h1 id="основы-docker-мониторинг" tabindex="-1">Основы Docker: Мониторинг <a class="header-anchor" href="#основы-docker-мониторинг" aria-label="Permalink to “Основы Docker: Мониторинг”">​</a></h1><p>Мониторинг Docker включает в себя сбор и анализ метрик как на уровне Docker-хоста (сервера, на котором запущен Docker Daemon), так и на уровне отдельных контейнеров.</p><h2 id="уровни-мониторинга-docker" tabindex="-1">Уровни мониторинга Docker <a class="header-anchor" href="#уровни-мониторинга-docker" aria-label="Permalink to “Уровни мониторинга Docker”">​</a></h2><ol><li><strong>Мониторинг Docker-хоста:</strong> Отслеживание использования ресурсов (CPU, память, диск, сеть) на сервере, где запущен Docker Daemon. Также включает мониторинг состояния самого Docker Daemon.</li><li><strong>Мониторинг контейнеров:</strong> Отслеживание использования ресурсов (CPU, память, диск, сеть) каждым запущенным контейнером, а также состояния их процессов и приложений.</li><li><strong>Мониторинг приложений внутри контейнеров:</strong> Сбор специфичных метрик от приложений, работающих внутри контейнеров (например, HTTP-запросы, задержка, ошибки, состояние базы данных).</li></ol><h2 id="инструменты-для-мониторинга-docker" tabindex="-1">Инструменты для мониторинга Docker <a class="header-anchor" href="#инструменты-для-мониторинга-docker" aria-label="Permalink to “Инструменты для мониторинга Docker”">​</a></h2><p>Существует множество инструментов для мониторинга Docker, как встроенных, так и сторонних.</p><h3 id="встроенные-инструменты-docker" tabindex="-1">Встроенные инструменты Docker <a class="header-anchor" href="#встроенные-инструменты-docker" aria-label="Permalink to “Встроенные инструменты Docker”">​</a></h3><ul><li><p><strong><code>docker stats</code>:</strong> Команда в реальном времени отображает статистику использования ресурсов (CPU, память, сеть, ввод/вывод) для запущенных контейнеров.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stats</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stats</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Эта команда полезна для быстрого просмотра текущей ситуации, но не сохраняет исторические данные.</p></li><li><p><strong><code>docker system df</code>:</strong> Отображает информацию об использовании дискового пространства, связанного с Docker (образы, контейнеры, локальные тома).</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> df</span></span></code></pre></div></li><li><p><strong><code>docker events</code>:</strong> Показывает поток событий Docker Daemon в реальном времени (запуск/остановка контейнеров, создание/удаление образов и т.д.).</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> events</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> events</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;type=container&#39;</span></span></code></pre></div><p>Полезно для отслеживания изменений состояния контейнеров.</p></li><li><p><strong>Логи контейнеров (<code>docker logs</code>):</strong> Хотя это не совсем мониторинг метрик, просмотр логов важен для диагностики проблем.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Следить за логами</span></span></code></pre></div></li></ul><h3 id="сторонние-инструменты-мониторинга" tabindex="-1">Сторонние инструменты мониторинга <a class="header-anchor" href="#сторонние-инструменты-мониторинга" aria-label="Permalink to “Сторонние инструменты мониторинга”">​</a></h3><p>Для более комплексного и долговременного мониторинга рекомендуется использовать специализированные инструменты:</p><ul><li><p><strong>cAdvisor (Container Advisor):</strong> Open-source агент от Google, который собирает метрики использования ресурсов и производительности от запущенных контейнеров. Обычно используется в связке с системами хранения и визуализации метрик, такими как Prometheus и Grafana.</p><ul><li>Предоставляет API для сбора данных.</li><li>Может работать как Docker-контейнер.</li></ul></li><li><p><strong>Prometheus:</strong> Open-source система мониторинга и оповещений, которая собирает метрики, периодически опрашивая цели (например, cAdvisor).</p><ul><li>Имеет мощный язык запросов (PromQL).</li><li>Хорошо интегрируется с Docker и Kubernetes.</li></ul></li><li><p><strong>Grafana:</strong> Open-source платформа для визуализации данных. Может отображать метрики, собранные Prometheus, InfluxDB, Elasticsearch и другими источниками.</p><ul><li>Предоставляет богатые возможности для создания дашбордов.</li><li>Широкое сообщество и множество готовых дашбордов.</li></ul></li><li><p><strong>Datadog:</strong> Коммерческая SaaS-платформа для мониторинга и аналитики, которая поддерживает Docker из коробки.</p><ul><li>Предоставляет агентов для сбора метрик и логов.</li><li>Интегрируется с множеством других сервисов.</li></ul></li><li><p><strong>New Relic:</strong> Коммерческая платформа для мониторинга производительности приложений (APM) и инфраструктуры, включая Docker.</p><ul><li>Предоставляет подробные метрики производительности приложений внутри контейнеров.</li></ul></li><li><p><strong>Dynatrace:</strong> Коммерческая платформа для мониторинга производительности и управления цифровым опытом, с глубокой поддержкой Docker и оркестраторов.</p></li><li><p><strong>InfluxDB:</strong> Open-source Time Series Database (TSDB), часто используется для хранения метрик, собранных Telegraf или другими агентами.</p></li><li><p><strong>Telegraf:</strong> Open-source агент для сбора метрик из различных источников (включая Docker) и записи их в различные хранилища (например, InfluxDB, Prometheus).</p></li><li><p><strong>Sysdig:</strong> Коммерческая платформа для мониторинга безопасности и производительности контейнеров, основанная на open-source инструменте Sysdig.</p></li></ul><h2 id="метрики-для-мониторинга-docker" tabindex="-1">Метрики для мониторинга Docker <a class="header-anchor" href="#метрики-для-мониторинга-docker" aria-label="Permalink to “Метрики для мониторинга Docker”">​</a></h2><p>При мониторинге Docker важно отслеживать следующие группы метрик:</p><h3 id="метрики-docker-хоста" tabindex="-1">Метрики Docker-хоста <a class="header-anchor" href="#метрики-docker-хоста" aria-label="Permalink to “Метрики Docker-хоста”">​</a></h3><ul><li><strong>Использование CPU:</strong> Общая загрузка процессора хост-машины. Высокая загрузка может указывать на перегрузку или проблемы с производительностью.</li><li><strong>Использование памяти:</strong> Объем использованной и доступной оперативной памяти на хосте. Недостаток памяти может привести к замедлению работы или OOM (Out Of Memory) ошибкам.</li><li><strong>Использование диска:</strong> Загрузка дисковой подсистемы (чтение/запись), свободное пространство. Высокая загрузка диска может быть узким местом.</li><li><strong>Сетевая активность:</strong> Объем входящего и исходящего сетевого трафика на хосте.</li><li><strong>Состояние Docker Daemon:</strong> Проверка, что Docker Daemon запущен и работает без ошибок.</li></ul><h3 id="метрики-контеинеров" tabindex="-1">Метрики контейнеров <a class="header-anchor" href="#метрики-контеинеров" aria-label="Permalink to “Метрики контейнеров”">​</a></h3><ul><li><strong>Использование CPU (%):</strong> Процент выделенного CPU, используемый контейнером.</li><li><strong>Использование памяти (bytes, %):</strong> Объем используемой памяти и процент от выделенного лимита. Превышение лимита может привести к throttling или OOM Kill.</li><li><strong>Сетевой трафик (bytes in/out):</strong> Объем входящего и исходящего сетевого трафика для контейнера.</li><li><strong>Блочные устройства (ввод/вывод):</strong> Статистика чтения и записи с диска контейнером.</li><li><strong>Состояние контейнера:</strong> Запущен, остановлен, перезапускается и т.д.</li><li><strong>Health Checks:</strong> Результаты проверок состояния, настроенных для контейнеров.</li></ul><h3 id="метрики-приложении-внутри-контеинеров" tabindex="-1">Метрики приложений внутри контейнеров <a class="header-anchor" href="#метрики-приложении-внутри-контеинеров" aria-label="Permalink to “Метрики приложений внутри контейнеров”">​</a></h3><p>Эти метрики зависят от конкретного приложения, но могут включать:</p><ul><li><strong>HTTP-метрики:</strong> Количество запросов, время ответа, ошибки (4xx, 5xx).</li><li><strong>Метрики баз данных:</strong> Количество соединений, задержка запросов, ошибки.</li><li><strong>Очереди сообщений:</strong> Размер очереди, задержка обработки.</li><li><strong>Пользовательские метрики:</strong> Специфичные для вашего приложения бизнес-метрики.</li></ul><h2 id="настроика-мониторинга-docker-с-помощью-prometheus-и-grafana-пример" tabindex="-1">Настройка мониторинга Docker с помощью Prometheus и Grafana (пример) <a class="header-anchor" href="#настроика-мониторинга-docker-с-помощью-prometheus-и-grafana-пример" aria-label="Permalink to “Настройка мониторинга Docker с помощью Prometheus и Grafana (пример)”">​</a></h2><ol><li><p><strong>Запустите cAdvisor как Docker-контейнер:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --name=cadvisor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --volume=/:/rootfs:ro</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --volume=/var/run:/var/run:ro</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --volume=/sys:/sys:ro</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --volume=/var/lib/docker/:/var/lib/docker:ro</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --publish=8080:8080</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    gcr.io/cadvisor/cadvisor:latest</span></span></code></pre></div><p>Теперь cAdvisor будет доступен на порту 8080 вашего хоста и начнет собирать метрики.</p></li><li><p><strong>Настройте Prometheus для сбора метрик из cAdvisor:</strong></p><p>В конфигурационном файле <code>prometheus.yml</code> добавьте job для опроса cAdvisor:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">scrape_configs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">job_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;cadvisor&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    static_configs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;localhost:8080&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>Запустите Prometheus, указав путь к конфигурационному файлу.</p></li><li><p><strong>Настройте Grafana для визуализации метрик Prometheus:</strong></p><ul><li>Добавьте Prometheus как источник данных в Grafana.</li><li>Создайте дашборды, используя запросы PromQL для отображения метрик Docker (например, использование CPU/памяти контейнерами, сетевой трафик). Существует множество готовых дашбордов Grafana для мониторинга Docker.</li></ul></li></ol><h2 id="лучшие-практики-мониторинга-docker" tabindex="-1">Лучшие практики мониторинга Docker <a class="header-anchor" href="#лучшие-практики-мониторинга-docker" aria-label="Permalink to “Лучшие практики мониторинга Docker”">​</a></h2><ul><li><strong>Мониторинг на всех уровнях:</strong> Отслеживайте как хост-машину, так и контейнеры и приложения внутри них.</li><li><strong>Использование централизованной системы мониторинга:</strong> Собирайте и визуализируйте метрики в одном месте для удобства анализа.</li><li><strong>Настройка оповещений (Alerting):</strong> Определите пороговые значения для ключевых метрик и настройте оповещения при их превышении для своевременного реагирования на проблемы.</li><li><strong>Сохранение исторических данных:</strong> Храните метрики за определенный период времени для анализа трендов и диагностики проблем, возникающих не сразу.</li><li><strong>Визуализация данных:</strong> Используйте дашборды для наглядного отображения ключевых метрик и быстрого выявления аномалий.</li><li><strong>Мониторинг состояния здоровья (Health Checks):</strong> Используйте health checks, определенные в Dockerfile или оркестраторе, и отслеживайте их результаты.</li><li><strong>Корреляция данных:</strong> Сопоставляйте метрики с логами и событиями для более глубокого анализа проблем.</li></ul><p>Эффективный мониторинг Docker позволяет вам поддерживать стабильность и производительность ваших контейнеризованных приложений, быстро выявлять и устранять проблемы, а также планировать ресурсы на основе данных об их использовании.</p>`,25)]))}const c=i(n,[["render",r]]);export{g as __pageData,c as default};
